node - <<'NODE'
const fs=require('fs');
const p='/home/administrator/.openclaw/openclaw.json';
const cfg=JSON.parse(fs.readFileSync(p,'utf8'));

const OLD='oc_b34019cc0cfae6d86efe0600b0803409';
const NEW='oc_0d162d83b615e8191e2b0bd6ede53a7b';

// 1) bindings: move awk-pop to NEW
cfg.bindings = Array.isArray(cfg.bindings)?cfg.bindings:[];
let touchedBinding=false;
for(const b of cfg.bindings){
  if(b?.agentId==='awk-pop' && b?.match?.channel==='feishu' && b?.match?.peer?.kind==='group'){
    b.match.accountId = b.match.accountId || 'default';
    b.match.peer.id = NEW;
    touchedBinding=true;
  }
}
if(!touchedBinding){
  cfg.bindings.unshift({agentId:'awk-pop',match:{channel:'feishu',accountId:'default',peer:{kind:'group',id:NEW}}});
}

// de-dup group bindings by (channel/account/kind/id), keep first
const seen=new Set();
cfg.bindings = cfg.bindings.filter(b=>{
  if(!(b&&b.match&&b.match.channel==='feishu'&&b.match.peer?.kind==='group')) return true;
  const key=`${b.match.channel}|${b.match.accountId||'default'}|${b.match.peer.kind}|${b.match.peer.id}`;
  if(seen.has(key)) return false;
  seen.add(key); return true;
});

// 2) feishu allowlist/group reply policy
cfg.channels ??= {};
cfg.channels.feishu ??= {};
const f=cfg.channels.feishu;
f.groupPolicy = f.groupPolicy || 'allowlist';
const allow = Array.isArray(f.groupAllowFrom)?f.groupAllowFrom.map(String):[];
const normalized = allow.filter(id=>id!==OLD && id!==`chat:${OLD}`);
if(!normalized.includes(NEW) && !normalized.includes(`chat:${NEW}`)) normalized.push(NEW);
if(!normalized.includes('oc_fbccca7a9adc4b863f05210185bc495e')) normalized.push('oc_fbccca7a9adc4b863f05210185bc495e');
f.groupAllowFrom = normalized;

f.groups ??= {};
if(f.groups[OLD]) delete f.groups[OLD];
f.groups[NEW] = {...(f.groups[NEW]||{}), requireMention:false};
f.groups['oc_fbccca7a9adc4b863f05210185bc495e'] = {...(f.groups['oc_fbccca7a9adc4b863f05210185bc495e']||{}), requireMention:false};

fs.writeFileSync(p, JSON.stringify(cfg,null,2));
console.log('patched');
console.log('awk-pop binding:', cfg.bindings.find(b=>b.agentId==='awk-pop'));
console.log('groupAllowFrom:', f.groupAllowFrom);
NODE
openclaw gateway restart
openclaw status --all | sed -n '1,220p'

